import torch
from torchvision import models, transforms
from PIL import Image
from io import BytesIO
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)

# Load pre-trained model and device (GPU or CPU)
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model = models.resnet50(pretrained=True).to(device)

# Define allowed image extensions
ALLOWED_EXTENSIONS = {'jpg', 'jpeg', 'png'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/classify', methods=['POST'])
def classify():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image = request.files['image']
    
    if image.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if not allowed_file(image.filename):
        return jsonify({'error': 'Invalid image format'}), 400
    
    filename = secure_filename(image.filename)
    image.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    
    # Load image using PIL
    img = Image.open(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    
    # Preprocess image (resize to 224x224, normalize pixel values)
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    
    img = transform(img)
    
    # Move image to device (GPU or CPU)
    img = img.to(device)
    
    # Run inference
    output = model(img.unsqueeze(0))
    
    # Get predicted class and confidence score
    _, predicted_class = torch.max(output, 1)
    confidence_score = torch.nn.functional.softmax(output, dim=1)[0][predicted_class]
    
    return jsonify({
        'class': list(model.class_to_idx.keys())[list(model.class_to_idx.values()).index(predicted_class.item())],
        'confidence': float(confidence_score.item())
    })

if __name__ == '__main__':
    app.config['UPLOAD_FOLDER'] = '/path/to/upload/folder'
    app.run(debug=True)